describe('Authentication Tests', () => {
  beforeEach(() => {
    cy.visit('/');
  });

  it('should navigate to login page', () => {
    cy.get('[data-cy="sign-in-button"]').first().click();
    cy.url().should('include', '/login');
    cy.get('[data-cy="login-form"]').should('be.visible');
  });

  it('should login with valid credentials', () => {
    cy.login(Cypress.env('username'), Cypress.env('password'));
    cy.get('[data-cy="user-menu"]').should('be.visible');
    cy.get('[data-cy="dashboard"]').should('be.visible');
  });

  it('should show error for invalid credentials', () => {
    cy.visit('/login');
    cy.get('[data-cy="username-input"]').type('invalid@email.com');
    cy.get('[data-cy="password-input"]').type('wrongpassword');
    cy.get('[data-cy="login-submit"]').click();
    cy.get('[data-cy="error-message"]').should('be.visible');
    cy.get('[data-cy="error-message"]').should('contain', 'Invalid credentials');
  });

  it('should validate required fields', () => {
    cy.visit('/login');
    cy.get('[data-cy="login-submit"]').click();
    cy.get('[data-cy="username-error"]').should('contain', 'Username is required');
    cy.get('[data-cy="password-error"]').should('contain', 'Password is required');
  });

  it('should handle logout', () => {
    cy.login(Cypress.env('username'), Cypress.env('password'));
    cy.logout();
    cy.url().should('not.include', '/dashboard');
    cy.get('[data-cy="sign-in-button"]').should('be.visible');
  });
});